import pytest
import requests

def test_create_observation_with_valid_loinc_code(
    base_url, clinician_auth_headers, existing_patient_id
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "code": {
            "coding": [
                {
                    "system": "http://loinc.org",
                    "code": "8867-4",
                    "display": "Heart rate"
                }
            ]
        },
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "valueQuantity": {"value": 72, "unit": "beats/min"}
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=clinician_auth_headers
    )
    assert resp.status_code == 201, resp.text
    body = resp.json()
    assert body["resourceType"] == "Observation"
    assert "id" in body
    coding = body["code"]["coding"][0]
    assert coding["system"] == "http://loinc.org"
    assert coding["code"] == "8867-4"

import pytest
import requests

def test_create_observation_missing_code_returns_422(
    base_url, clinician_auth_headers, existing_patient_id
):
    payload = {
        "resourceType": "Observation",
        "status": "final",
        "subject": {"reference": f"Patient/{existing_patient_id}"}
    }
    resp = requests.post(
        f"{base_url}/Observation",
        json=payload,
        headers=clinician_auth_headers
    )
    assert resp.status_code == 422, resp.text
    body = resp.json()
    error_text = str(body).lower()
    assert any(
        kw in error_text for kw in ("code", "missing", "required", "invalid")
    ), f"Expected validation error mentioning 'code', got: {body}"

